test_traj.command:
echo "Checking if the comparison always returns true..." && alive-tv <(cat <<'EOF'
define i1 @compare_abs(i8 %x) {
  %sext32 = sext i8 %x to i32
  %abs32 = call i32 @llvm.abs.i32(i32 %sext32, i1 true)
  %trunc32 = trunc i32 %abs32 to i16
  %sext16 = sext i8 %x to i16
  %abs16 = call i16 @llvm.abs.i16(i16 %sext16, i1 true)
  %cmp = icmp eq i16 %trunc32, %abs16
  ret i1 %cmp
}
EOF
) <(cat <<'EOF'
define i1 @compare_abs(i8 %x) {
  ret i1 true
}
EOF
) 2>&1

alive-tv <(cat <<'EOF'
define i16 @abs_bug_demo(i32 %x) {
  %abs_val = call i32 @llvm.abs.i32(i32 %x, i1 true)
  %trunc = trunc i32 %abs_val to i16
  ret i16 %trunc
}
EOF
) <(cat <<'EOF'
define i16 @abs_bug_transformed(i32 %x) {
  %trunc_first = trunc i32 %x to i16
  %abs_val = call i16 @llvm.abs.i16(i16 %trunc_first, i1 false)
  ret i16 %abs_val
}
EOF
) 2>&1

alive-tv <(cat <<'EOF'
define i16 @original(i8 %x) {
  %sext = sext i8 %x to i32
  %abs32 = call i32 @llvm.abs.i32(i32 %sext, i1 true)
  %trunc = trunc i32 %abs32 to i16
  ret i16 %trunc
}
EOF
) <(cat <<'EOF'
define i16 @transformed(i8 %x) {
  %abs8 = call i8 @llvm.abs.i8(i8 %x, i1 false)
  %zext = zext i8 %abs8 to i16
  ret i16 %zext
}
EOF
) 2>&1

alive-tv <(cat <<'EOF'
define i16 @test_value(i8 %x) {
  %sext = sext i8 %x to i32
  %abs32 = call i32 @llvm.abs.i32(i32 %sext, i1 true)
  %trunc = trunc i32 %abs32 to i16
  ret i16 %trunc
}
EOF
) <(cat <<'EOF'
define i16 @test_value(i8 %x) {
  %abs8 = call i8 @llvm.abs.i8(i8 %x, i1 false)
  %zext = zext i8 %abs8 to i16
  ret i16 %zext
}
EOF
) 2>&1 | tail -20
